import express from 'express';
const app = express();
app.use(express.json());

app.get('/navy-window', (req, res) => {
  try {
    // Simulate brittle edge exposure
    if (Math.random() > 0.8) {
      throw new Error('Brittle edge exposed');
    }
    res.status(200).send('Navy window is safe');
  } catch (error) {
    res.status(500).send(error.message);
  }
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});
```

