```typescript
async function fetchClimateData(url: string, maxRetries = 3): Promise<any> {
    let retryCount = 0;
    const maxDelay = 2000;

    while (retryCount < maxRetries) {
        try {
            const response = await fetch(url);
            if (!response.ok) throw new Error('HTTP error ' + response.status);
            return await response.json();
        } catch (error) {
            console.error(`Attempt ${retryCount + 1} failed:`, error);
            retryCount++;
            await new Promise(resolve => setTimeout(resolve, Math.min(maxDelay * Math.pow(2, retryCount), maxDelay)));
        }
    }

    throw new Error('Max retries exceeded');
}
```

