```typescript
function getRolloutDate(glassType: string): Date {
    const baseDate = new Date('2023-01-01');
    if (glassType === 'tempered') {
        return new Date(baseDate.setMonth(baseDate.getMonth() + 6));
    } else if (glassType === 'safety') {
        return new Date(baseDate.setMonth(baseDate.getMonth() + 3));
    }
    throw new Error('Invalid glass type');
}
```

